<div x-data="{ open: false }" class="flex justify-center">
    <!-- Trigger -->
    <button x-on:click="open = true" type="button"
        class="cursor-pointer group hover:bg-primary transition ease-in duration-75 inline-flex items-center justify-center space-x-3 w-full bg-white rounded-sm py-4 px-3"
        style="box-shadow: 0px 1px 5px rgba(0, 0, 0, 0.25)">
        <span class="text-primary group-hover:text-white text-lg font-bold">مشاركة</span>
        <svg class="size-6 text-primary group-hover:text-white" data-slot="icon" aria-hidden="true" fill="none"
            stroke-width="1.5" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
            <path
                d="M7.217 10.907a2.25 2.25 0 1 0 0 2.186m0-2.186c.18.324.283.696.283 1.093s-.103.77-.283 1.093m0-2.186 9.566-5.314m-9.566 7.5 9.566 5.314m0 0a2.25 2.25 0 1 0 3.935 2.186 2.25 2.25 0 0 0-3.935-2.186Zm0-12.814a2.25 2.25 0 1 0 3.933-2.185 2.25 2.25 0 0 0-3.933 2.185Z"
                stroke-linecap="round" stroke-linejoin="round"></path>
        </svg>
    </button>

    <!-- Modal -->
    <div x-show="open" style="display: none" x-on:keydown.escape.prevent.stop="open = false" role="dialog"
        aria-modal="true" x-id="['modal-title']" :aria-labelledby="$id('modal-title')"
        class="fixed inset-0 z-50 overflow-y-auto">
        <!-- Overlay -->
        <div x-show="open" x-transition.opacity class="fixed inset-0 bg-black/40"></div>

        <!-- Panel -->
        <div x-show="open" x-transition x-on:click="open = false"
            class="relative flex min-h-screen items-center justify-center p-4">
            <div x-on:click.stop x-trap.noscroll.inert="open"
                class="relative min-w-96 max-w-xl rounded-sm bg-white shadow-lg py-6">
                <!-- Title -->
                <h2 class="font-medium text-gray-800 pb-4 px-6 border-b border-gray-300" :id="$id('modal-title')">
                    مشاركة الإعلان رقم: #2024-23232</h2>

                <!-- Content -->
                <div class="mt-6 text-gray-500 max-w-xs mx-auto px-3 space-y-6">
                    <div class="flex items-center justify-center space-x-6">
                        <button type="button"
                            class="cursor-pointer size-12 rounded-full flex items-center justify-center shadow">
                            <svg class="size-12" width="667" height="665" viewBox="0 0 667 665" fill="none"
