                            <input id="query" type="text" name="query"
                                class="col-start-1 row-start-1 block w-full appearance-none bg-[#f1f1f1] placeholder:text-primary-gray border-0 p-4 rounded-e-sm shadow focus:ring-primary text-sm"
                                value="{{ url()->full() }}" />
                        </div>
